#!/bin/bash
set -euo pipefail

speeds=(20 30 40 50)
nodes=(100 200 300 400 500)

cd /home/daniel/ns-3-dev

# Clear old CSV generated by the simulation.
rm -f manet_results.csv

for n in "${nodes[@]}"
do
  for s in "${speeds[@]}"
  do
    echo "Running: Nodes=$n Speed=$s"
    ./ns3 run "scratch/manet-opportunistic-meanfield-routing --nodes=$n --destination=$((n-1)) --speedMax=$s --speedMin=$s"
  done
done

echo "Done. Results written to /home/daniel/ns-3-dev/manet_results.csv"
